  parameter bit [15:0] A_VALUES[20] = '{
      lc_ctrl_state_pkg::A0,
      lc_ctrl_state_pkg::A1,
      lc_ctrl_state_pkg::A2,
      lc_ctrl_state_pkg::A3,
      lc_ctrl_state_pkg::A4,
