      lc_state_to_bin(LcStProdEnd),
      lc_state_to_bin(LcStRma),
      lc_state_to_bin(LcStScrap)
  };

  // Array of valid LC states in binary representation
  parameter lc_count_bin_t ValidLcCountsBin[NumLcCountStates] = '{
