  parameter uint OTP_PROG_DDATA_WIDTH = 1;

  typedef struct packed {
    lc_ctrl_pkg::lc_tx_t lc_dft_en_o;
    lc_ctrl_pkg::lc_tx_t lc_nvm_debug_en_o;
