      `DV_ASSERT_CTRL_REQ("OtpProgReqHighUntilAck_A", 1)
      `DV_ASSERT_CTRL_REQ("OtpProgAckAssertedOnlyWhenReqAsserted_A", 1)
      `DV_ASSERT_CTRL_REQ("KmacIfSyncReqAckAckNeedsReq", 1)
